INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-master-mates-c2-l3','sem-master-mates-c2','Scholar''s Mate','Deliver mate in one','🎓','mate',20,0,'[]','[{"id":"info","kind":"info","coach":"The four-move attack: Qxf7 — the bishop guards the queen. Beware this trap!","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p2Q/2B1P3/8/PPPP1PPP/RNB1K1NR w - - 0 1"},{"id":"mate","kind":"move","coach":"Deliver Scholar''s Mate!","fen":"r1bqkb1r/pppp1ppp/2n2n2/4p2Q/2B1P3/8/PPPP1PPP/RNB1K1NR w - - 0 1","solution":["h5:f7"],"highlight":["f7"],"successText":"Checkmate! 🏆","failText":"Not mate — find the finishing move.","tag":"mate"}]',2);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-master-games-c1-l1','sem-master-games-c1','The Opera Game','Morphy, 1858','🎭','famous',25,0,'[]','[{"id":"intro","kind":"info","coach":"Morphy''s masterpiece: a queen sacrifice (Qb8+!!) sets up a rook mate. Watch the finish.","fen":"4kb1r/p2rqppp/5n2/1B2p1B1/4P3/1Q6/PPP2PPP/2K4R w k - 0 14"},{"id":"watch","kind":"observe","coach":"Watch the combination unfold…","fen":"4kb1r/p2rqppp/5n2/1B2p1B1/4P3/1Q6/PPP2PPP/2K4R w k - 0 14","moves":["h1:d1","e7:e6","b5:d7","f6:d7","b3:b8","d7:b8","d1:d8"]}]',0);
INSERT INTO lessons (id,class_id,title,subtitle,emoji,tag,xp,is_exam,prerequisites,steps,sort_order) VALUES ('sem-master-games-c1-l2','sem-master-games-c1','The Evergreen Game','Anderssen, 1852','🎭','famous',25,0,'[]','[{"id":"intro","kind":"info","coach":"Anderssen''s brilliancy ends with Qxd7+!! and a bishop net. Watch the combination.","fen":"1r2k1r1/pbppnp1p/1b3P2/8/Q7/B1PB1q2/P4PPP/3R2K1 w - - 0 21"},{"id":"watch","kind":"observe","coach":"Watch the combination unfold…","fen":"1r2k1r1/pbppnp1p/1b3P2/8/Q7/B1PB1q2/P4PPP/3R2K1 w - - 0 21","moves":["a4:d7","e8:d7","d3:f5","d7:e8","f5:d7","e8:f8","a3:e7"]}]',1);
